import { useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import MedicalDisclaimer from "@/components/MedicalDisclaimer";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import SliderInput from "@/components/SliderInput";
import FAQItem from "@/components/FAQItem";


const FAQS = [
  { q: "How do I convert feet and inches to centimeters?", a: "Multiply total inches by 2.54 cm/inch. First convert feet and inches to total inches: (feet  x  12) + inches. Then multiply by 2.54. Example: 5'10\" = (5  x  12 + 10) = 70 inches  x  2.54 = 177.8 cm. The conversion factor 1 inch = 2.54 cm is exact by international agreement." },
  { q: "How do I convert centimeters to feet and inches?", a: "Divide centimeters by 2.54 to get total inches. Then divide by 12 to get feet (the whole number). The remainder is the inches. Example: 180 cm  x  2.54 = 70.87 inches - 70  x  12 = 5 feet, remainder 10.87 inches - 5'10.9\"." },
  { q: "What is the average height for men and women?", a: "US averages: men 5'9\" (175.3 cm), women 5'3.6\" (161.3 cm). Global averages are lower: men ~5'7\" (171 cm), women ~5'2\" (159 cm). The Netherlands has the tallest average population: men ~6'0\" (182 cm), women ~5'7\" (171 cm). Height averages have increased significantly over the past century due to improved nutrition." },
  { q: "How do I predict a child's adult height?", a: "The mid-parental height formula: For boys - (Father's height + Mother's height + 5 inches)  x  2. For girls - (Father's height + Mother's height - 5 inches)  x  2. The result has a - inch (- cm) range of accuracy. This captures about 80% of children's adult heights when accounting for the range." },
  { q: "When do boys and girls stop growing?", a: "Girls typically stop growing 1-2 years after their first menstrual period, usually around ages 14-16. Boys continue growing later and typically reach their full height between 17-20. Both sexes can see small growth spurts into their early 20s. Boys grow more total height than girls during puberty." },
  { q: "Does height affect health outcomes?", a: "Research shows correlations between height and certain health factors. Taller individuals have statistically lower rates of heart disease but slightly higher rates of some cancers. Height is influenced by genetics (60-80%), nutrition, sleep, and general childhood health. These are population-level correlations, not deterministic for individuals." },
  { q: "How accurate is the mid-parental height prediction?", a: "The mid-parental formula captures genetics, which accounts for about 60-80% of height variation. It does not account for nutrition, chronic illness, hormonal factors, or sleep. In research studies, 80% of children land within - inches of the mid-parental prediction. For greater accuracy, pediatricians use growth charts based on current height percentile." },
  { q: "What are common height conversion mistakes?", a: "The most common mistake is using 2.5 instead of 2.54 for the inches-to-cm conversion, which introduces 1.6% error (about 2-3 cm for typical heights). Another mistake is forgetting that 1 foot = 12 inches (not 10). Always convert feet to total inches first before multiplying by 2.54." },
];

const HEIGHT_REFERENCE = [
  ["5'0\" (152.4 cm)", "Short for both sexes globally"],
  ["5'4\" (162.6 cm)", "Average US woman"],
  ["5'7\" (170.2 cm)", "Average global man"],
  ["5'9\" (175.3 cm)", "Average US man"],
  ["6'0\" (182.9 cm)", "Tall for men globally"],
  ["6'3\" (190.5 cm)", "Very tall - top 5% for US men"],
  ["6'6\" (198.1 cm)", "NBA player average"],
  ["7'0\" (213.4 cm)", "Exceptionally tall - less than 0.001% of population"],
];

export default function HeightCalculator() {
  const [mode, setMode] = useState<"ftcm" | "predict">("ftcm");
  const [feet, setFeet] = useState(5);
  const [inches, setInches] = useState(10);
  const [cm, setCm] = useState(178);
  const [fatherFt, setFatherFt] = useState(5);
  const [fatherIn, setFatherIn] = useState(11);
  const [motherFt, setMotherFt] = useState(5);
  const [motherIn, setMotherIn] = useState(5);
  const [gender, setGender] = useState<"male" | "female">("male");

  const totalInches = feet * 12 + inches;
  const cmFromFt = totalInches * 2.54;
  const ftFromCm = Math.floor(cm / 30.48);
  const inFromCm = Math.round((cm % 30.48) / 2.54);

  const fatherCm = (fatherFt * 12 + fatherIn) * 2.54;
  const motherCm = (motherFt * 12 + motherIn) * 2.54;
  const predictedCm = gender === "male" ? (fatherCm + motherCm + 13) / 2 : (fatherCm + motherCm - 13) / 2;
  const predictedFt = Math.floor(predictedCm / 30.48);
  const predictedIn = Math.round((predictedCm % 30.48) / 2.54);
  const minCm = predictedCm - 10;
  const maxCm = predictedCm + 10;

  return (
    <>
      <SEOHead
        title="Free Height Calculator Online - Convert Height and Predict Adult Height Instantly | CalcHive"
        description="Free online height calculator. Convert height between feet and inches and centimeters or predict a child's adult height instantly. 100% free for everyone, no signup required."
        canonical="/height-calculator"
        keywords="free height calculator, height converter free online, feet inches to centimeters calculator free, child adult height predictor free, how tall will I be calculator free"
        category="Health Calculators"
        faqs={FAQS}
      />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8">
          <span className="text-xs font-semibold uppercase tracking-widest text-cyan-600 dark:text-cyan-400 bg-cyan-50 dark:bg-cyan-950/50 px-3 py-1 rounded-full mb-4 inline-block">Measurement</span>
          <h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Height Calculator Online</h1>
          <p className="text-muted-foreground leading-relaxed">Use this free height calculator to convert height between feet, inches, and centimeters or estimate adult height. This height converter free online also works as a feet inches to centimeters calculator free, child adult height predictor free, and how tall will I be calculator free.</p>
        </div>
        <AdPlaceholder size="banner" className="mb-8" />
        <div className="flex gap-2 mb-6">
          {[["ftcm", "Height Converter"], ["predict", "Predict Adult Height"]].map(([v, l]) => (
            <button key={v} onClick={() => setMode(v as "ftcm" | "predict")} className={`flex-1 py-2 rounded-xl text-sm font-semibold border transition-all ${mode === v ? "bg-cyan-600 text-white border-cyan-600" : "bg-card text-muted-foreground border-border hover:border-cyan-400"}`}>{l}</button>
          ))}
        </div>
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          {mode === "ftcm" ? (
            <>
              <div className="space-y-6 mb-8">
                <p className="text-sm font-semibold text-muted-foreground">Feet &amp; Inches to Centimeters</p>
                <SliderInput id="feet" label="Feet" value={feet} min={0} max={9} step={1} onChange={setFeet} format={v => `${v} ft`} testId="input-feet" />
                <SliderInput id="inches" label="Inches" value={inches} min={0} max={11} step={1} onChange={setInches} format={v => `${v}"`} testId="input-inches" />
              </div>
              <motion.div key={`${feet}-${inches}`} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
                <div className="bg-gradient-to-br from-cyan-500 to-cyan-700 rounded-2xl p-6 mb-4 text-center shadow-lg">
                  <p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">{feet}'{inches}" equals</p>
                  <p className="text-5xl font-black text-white tracking-tight" data-testid="result-cm">{cmFromFt.toFixed(1)} cm</p>
                  <p className="text-white/70 text-sm mt-1">{totalInches} total inches  x  2.54</p>
                </div>
                <div className="mb-6">
                  <p className="text-sm font-semibold text-muted-foreground mb-4">Centimeters to Feet &amp; Inches</p>
                  <SliderInput id="cm" label="Centimeters" value={cm} min={50} max={250} step={1} onChange={setCm} format={v => `${v} cm`} testId="input-cm" />
                </div>
                <div className="bg-accent/60 border border-border rounded-xl p-4 text-center">
                  <p className="text-xs text-muted-foreground font-medium mb-1">{cm} cm equals</p>
                  <p className="text-2xl font-extrabold text-foreground">{ftFromCm}' {inFromCm}"</p>
                </div>
              </motion.div>
            </>
          ) : (
            <>
              <div className="space-y-5 mb-8">
                <div className="mb-2">
                  <label className="text-sm font-semibold text-foreground mb-2 block">Child's Gender</label>
                  <div className="flex gap-2">
                    {[["male", "Male"], ["female", "Female"]].map(([v, l]) => <button key={v} onClick={() => setGender(v as "male" | "female")} className={`flex-1 py-2 rounded-xl text-sm font-semibold border transition-all ${gender === v ? "bg-cyan-600 text-white border-cyan-600" : "bg-card text-muted-foreground border-border"}`}>{l}</button>)}
                  </div>
                </div>
                <p className="text-sm font-semibold text-muted-foreground">Father's Height</p>
                <SliderInput id="fft" label="Feet" value={fatherFt} min={4} max={7} step={1} onChange={setFatherFt} format={v => `${v} ft`} testId="input-father-ft" />
                <SliderInput id="fin" label="Inches" value={fatherIn} min={0} max={11} step={1} onChange={setFatherIn} format={v => `${v}"`} testId="input-father-in" />
                <p className="text-sm font-semibold text-muted-foreground">Mother's Height</p>
                <SliderInput id="mft" label="Feet" value={motherFt} min={4} max={7} step={1} onChange={setMotherFt} format={v => `${v} ft`} testId="input-mother-ft" />
                <SliderInput id="min_" label="Inches" value={motherIn} min={0} max={11} step={1} onChange={setMotherIn} format={v => `${v}"`} testId="input-mother-in" />
              </div>
              <motion.div key={`${fatherFt}-${fatherIn}-${motherFt}-${motherIn}-${gender}`} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
                <div className="bg-gradient-to-br from-cyan-500 to-cyan-700 rounded-2xl p-6 text-center shadow-lg">
                  <p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Predicted Adult Height</p>
                  <p className="text-4xl font-black text-white tracking-tight" data-testid="result-predicted">{predictedFt}' {predictedIn}" / {predictedCm.toFixed(0)} cm</p>
                  <p className="text-white/70 text-sm mt-1">Typical range: {Math.floor(minCm/30.48)}'{Math.round((minCm%30.48)/2.54)}" - {Math.floor(maxCm/30.48)}'{Math.round((maxCm%30.48)/2.54)}" (- inches)</p>
                </div>
              </motion.div>
            </>
          )}
        </section>
        <MedicalDisclaimer /><ShareButton />

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Convert Height Between Feet Inches and Centimeters for Free</h2>
          <div className="bg-accent/60 border border-border rounded-2xl p-5 font-mono text-sm text-foreground space-y-1">
            <p>Feet/Inches - CM: Total Inches  x  2.54</p>
            <p>CM - Feet/Inches: CM  x  2.54 = total inches; then  x  12 for feet</p>
            <p>Mid-parental (Boy): (Father + Mother + 5 in)  x  2</p>
            <p>Mid-parental (Girl): (Father + Mother - 5 in)  x  2</p>
            <p className="text-xs text-muted-foreground mt-2">1 inch = 2.54 cm (exact) - 1 foot = 12 inches - 1 foot = 30.48 cm</p>
          </div>

          <h2 className="text-2xl font-bold text-foreground">How to Predict a Child's Adult Height for Free</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["Height", "Context"].map(h => <th key={h} className="text-left py-3 px-4 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {HEIGHT_REFERENCE.map(([height, context]) => (
                  <tr key={height} className="hover:bg-muted/30">
                    <td className="py-2.5 px-4 font-bold text-cyan-600 dark:text-cyan-400">{height}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{context}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>

          <h2 className="text-2xl font-bold text-foreground">Free Height Converter and Predictor for Everyone</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["Feet & Inches", "Total Inches", "Centimeters", "Meters"].map(h => <th key={h} className="text-left py-3 px-4 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {[[4,10],[5,0],[5,2],[5,4],[5,6],[5,8],[5,10],[5,11],[6,0],[6,2],[6,4],[6,6]].map(([f, i]) => {
                  const ti = f * 12 + i;
                  const c = ti * 2.54;
                  return (
                    <tr key={`${f}-${i}`} className={`hover:bg-muted/30 ${f === feet && i === inches ? "bg-cyan-50 dark:bg-cyan-950/20 font-semibold" : ""}`}>
                      <td className="py-2.5 px-4 font-bold text-cyan-600 dark:text-cyan-400">{f}'{i}"</td>
                      <td className="py-2.5 px-4 text-muted-foreground">{ti}"</td>
                      <td className="py-2.5 px-4 text-foreground font-medium">{c.toFixed(1)} cm</td>
                      <td className="py-2.5 px-4 text-muted-foreground">{(c/100).toFixed(2)} m</td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        </section>

        <section className="mb-8">
          <h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3>
          <div className="space-y-3">{FAQS.map(f => <FAQItem key={f.q} q={f.q} a={f.a} />)}</div>
        </section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/height-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


